"""Generate all MiniLab CSV summary tables."""

from __future__ import annotations

import sys
from pathlib import Path

PROJECT_ROOT = Path(__file__).resolve().parents[1]
if str(PROJECT_ROOT) not in sys.path:
    sys.path.insert(0, str(PROJECT_ROOT))

from experiments.run_experiments import (
    RESULTS_DIR,
    collect_summary_metrics,
    save_advanced_research_tables,
    save_core_research_tables,
    save_urban_tables,
)


def make_all_summary_tables(results_dir: Path | str = RESULTS_DIR) -> list[Path]:
    """Save all CSV tables generated by the core experiment suite."""

    output_dir = Path(results_dir)
    output_dir.mkdir(parents=True, exist_ok=True)
    summary_path = output_dir / "summary_metrics.csv"
    collect_summary_metrics().to_csv(summary_path, index=False)
    return [
        summary_path,
        *save_core_research_tables(output_dir),
        *save_urban_tables(output_dir),
        *save_advanced_research_tables(output_dir),
    ]


def main() -> None:
    for path in make_all_summary_tables():
        print(path)


if __name__ == "__main__":
    main()
